
.succubus-card {
  width: 100%;
  background: linear-gradient(145deg, #1a0b16 0%, #2a081a 100%);
  border: 1px solid #8e1b4b;
  border-radius: 8px;
  box-shadow:
    0 0 15px rgba(220, 20, 60, 0.3),
    inset 0 0 20px rgba(142, 27, 75, 0.4);
  color: #f8bbd0;
  font-family: 'Microsoft YaHei', sans-serif;
  padding: 12px;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.collapse-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  user-select: none;
}

.collapse-title {
  color: #ff4081;
  font-size: 1.1em;
  font-weight: bold;
  text-shadow: 0 0 8px #f50057;
  letter-spacing: 2px;
}

.collapse-btn {
  background: linear-gradient(145deg, #d81b60, #880e4f);
  border: 1px solid #ff4081;
  border-radius: 4px;
  color: #ffffff;
  font-size: 0.75em;
  padding: 4px 10px;
  cursor: pointer;
  transition: all 0.3s ease;

  &:hover {
    background: linear-gradient(145deg, #ff4081, #d81b60);
    box-shadow: 0 0 10px rgba(255, 64, 129, 0.5);
  }
}

.collapsible-content {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

/* 分页导航 */
.tab-nav {
  display: flex;
  border-bottom: 2px solid #880e4f;
  gap: 2px;
}

.tab-btn {
  flex: 1;
  padding: 6px 0;
  border: none;
  border-radius: 4px 4px 0 0;
  background: rgba(0, 0, 0, 0.4);
  color: #ce93d8;
  font-size: 0.8em;
  font-weight: bold;
  cursor: pointer;
  transition: all 0.25s ease;
  letter-spacing: 1px;
  position: relative;

  &:hover {
    background: rgba(216, 27, 96, 0.3);
    color: #ff80ab;
  }

  &.active {
    background: rgba(216, 27, 96, 0.5);
    color: #ff4081;
    text-shadow: 0 0 6px rgba(255, 64, 129, 0.6);
    border-bottom: 2px solid #ff4081;
    margin-bottom: -2px;
  }
}

.tab-badge {
  position: absolute;
  top: -4px;
  right: -4px;
  background: #ff4081;
  color: #fff;
  font-size: 0.65em;
  font-weight: bold;
  min-width: 16px;
  height: 16px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  opacity: 1;
  z-index: 10;
}

.tab-badge.reward-badge {
  top: -4px;
  right: 14px;
  background: #ffc107;
  color: #333;
  border: 2px solid #ff9800;
  box-shadow: 0 0 6px rgba(255, 193, 7, 0.6);
}

.tab-pane {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

/* 区块样式 */
.section-box {
  background: rgba(0, 0, 0, 0.5);
  border-left: 3px solid #d81b60;
  border-radius: 4px;
  padding: 8px;
}

.section-title {
  color: #ff80ab;
  font-size: 0.9em;
  font-weight: bold;
  margin-bottom: 6px;
  text-shadow: 0 0 4px rgba(255, 128, 171, 0.5);
}

.resource-bar,
.resource-standalone {
  margin-bottom: 8px;
  padding: 8px 12px;
  background: rgba(0, 0, 0, 0.35);
  border-radius: 4px;
  border-left: 3px solid #d81b60;
}

.resource-line {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 4px;
}

.resource-label {
  color: #ce93d8;
  font-size: 0.8em;
  min-width: 130px;
}

.resource-value {
  color: #ffffff;
  text-shadow: 0 0 3px #ff4081;
  font-size: 0.8em;
  font-weight: 500;
}

.data-row {
  display: flex;
  justify-content: space-between;
  font-size: 0.8em;
  margin-bottom: 4px;
  line-height: 1.4;
}

.data-label {
  color: #ce93d8;
}

.data-value {
  color: #ffffff;
  text-shadow: 0 0 3px #ff4081;
}

/* 等级和经验条样式 */
.level-display {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 6px;
}

.level-badge {
  background: linear-gradient(135deg, #d81b60, #880e4f);
  color: #fff;
  font-size: 0.8em;
  font-weight: bold;
  padding: 3px 10px;
  border-radius: 10px;
  text-shadow: 0 0 6px rgba(255, 64, 129, 0.8);
  white-space: nowrap;
}

.attr-points-badge {
  float: right;
  font-size: 0.7em;
  color: #ffd54f;
  font-weight: normal;
}

.exp-bar-container {
  flex: 1;
  height: 16px;
  background: rgba(0, 0, 0, 0.4);
  border-radius: 8px;
  overflow: hidden;
  position: relative;
  border: 1px solid rgba(216, 27, 96, 0.5);
}

.exp-bar {
  height: 100%;
  background: linear-gradient(90deg, #880e4f, #d81b60, #ff4081);
  transition: width 0.3s ease;
  box-shadow: 0 0 10px rgba(255, 64, 129, 0.6);
}

.exp-text {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  font-size: 0.7em;
  color: #fff;
  text-shadow: 0 0 4px rgba(0, 0, 0, 0.8);
  white-space: nowrap;
}

.attr-points-hint {
  color: #ffd54f;
  font-size: 0.8em;
  text-align: center;
  padding: 4px;
  background: rgba(255, 213, 79, 0.1);
  border-radius: 4px;
  animation: pulse-glow 2s infinite;
}

/* DND属性样式 */
.dnd-attributes {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 6px;
}

.attr-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: rgba(0, 0, 0, 0.3);
  padding: 4px 8px;
  border-radius: 4px;
  border-left: 2px solid #d81b60;
}

.attr-label {
  color: #ce93d8;
  font-size: 0.8em;
  min-width: 70px;
}

.attr-value-container {
  display: flex;
  align-items: center;
  gap: 4px;
}

.attr-value {
  color: #fff;
  font-size: 0.9em;
  font-weight: bold;
  min-width: 20px;
  text-align: center;
}

.attr-plus-btn {
  background: linear-gradient(135deg, #4caf50, #2e7d32);
  border: none;
  color: #fff;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  font-size: 0.8em;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s ease;

  &:hover {
    transform: scale(1.1);
    box-shadow: 0 0 8px rgba(76, 175, 80, 0.6);
  }

  &:active {
    transform: scale(0.95);
  }
}

/* 任务页样式 */
.current-task {
  border-left-color: #ff4081;
  box-shadow: 0 0 8px rgba(255, 64, 129, 0.2);
}

@keyframes pulse-glow {
  0%, 100% { text-shadow: 0 0 3px #ff4081; }
  50% { text-shadow: 0 0 10px #ff4081, 0 0 20px rgba(255, 64, 129, 0.4); }
}

.task-desc-text {
  color: #f48fb1;
  font-size: 0.8em;
  margin: 4px 0;
  padding: 4px 8px;
  border-left: 2px solid #d81b60;
  background: rgba(216, 27, 96, 0.1);
  border-radius: 2px;
}

.task-card {
  background: rgba(216, 27, 96, 0.08);
  border: 1px solid rgba(216, 27, 96, 0.25);
  border-radius: 4px;
  padding: 8px;
  margin-bottom: 6px;
  transition: all 0.2s ease;

  &:hover {
    border-color: rgba(216, 27, 96, 0.5);
    background: rgba(216, 27, 96, 0.15);
  }

  &.inactive {
    opacity: 0.6;

    &:hover {
      opacity: 0.8;
    }
  }
}

.task-card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 4px;
  gap: 6px;
}

.debug-complete-btn {
  background: linear-gradient(135deg, #4caf50, #2e7d32);
  border: 1px solid #81c784;
  border-radius: 4px;
  color: #fff;
  font-size: 0.7em;
  padding: 2px 6px;
  cursor: pointer;
  transition: all 0.2s ease;
  margin-left: auto;

  &:hover {
    transform: scale(1.1);
    box-shadow: 0 0 8px rgba(76, 175, 80, 0.6);
  }

  &:active {
    transform: scale(0.95);
  }
}

.task-level {
  color: #ff80ab;
  font-weight: bold;
  font-size: 0.8em;
}

.task-status-tag {
  font-size: 0.7em;
  padding: 2px 6px;
  border-radius: 3px;
  font-weight: bold;

  &.status-pending {
    background: rgba(255, 152, 0, 0.3);
    color: #ffb74d;
  }
  &.status-active {
    background: rgba(255, 64, 129, 0.3);
    color: #ff4081;
    animation: pulse-glow 1.5s ease-in-out infinite;
  }
  &.status-done {
    background: rgba(76, 175, 80, 0.3);
    color: #81c784;
  }
  &.status-failed {
    background: rgba(244, 67, 54, 0.3);
    color: #ef9a9a;
  }
  &.status-ignored {
    background: rgba(158, 158, 158, 0.3);
    color: #9e9e9e;
  }
}

.task-card-reward {
  display: flex;
  gap: 12px;
  font-size: 0.75em;
  color: #81c784;
  margin-bottom: 4px;
}

.task-card-penalty {
  display: flex;
  gap: 12px;
  font-size: 0.75em;
  color: #ef9a9a;
  margin-bottom: 6px;
}

.task-buttons {
  display: flex;
  gap: 6px;
  margin-top: 8px;
}

.task-btn {
  border-radius: 4px;
  font-size: 0.7em;
  font-weight: bold;
  cursor: pointer;
  transition: all 0.3s ease;
  padding: 4px 8px;
  border: 1px solid;

  &:active {
    transform: scale(0.98);
  }
}

.accept-btn {
  flex: 2;
  background: linear-gradient(145deg, #d81b60, #880e4f);
  border-color: #ff4081;
  color: #ffffff;
  text-shadow: 0 0 4px rgba(255, 64, 129, 0.5);

  &:hover {
    background: linear-gradient(145deg, #ff4081, #d81b60);
    box-shadow: 0 0 10px rgba(255, 64, 129, 0.5);
  }

  &:disabled {
    opacity: 0.4;
    cursor: not-allowed;
  }
}

.giveup-btn {
  flex: 2;
  background: linear-gradient(145deg, #5c1818, #3d0f0f);
  border-color: #8b0000;
  color: #ff9999;

  &:hover {
    background: linear-gradient(145deg, #8b0000, #5c1818);
    box-shadow: 0 0 8px rgba(139, 0, 0, 0.5);
  }
}

.ignore-btn {
  flex: 1;
  background: linear-gradient(145deg, #2a2a2a, #1a1a1a);
  border-color: #555;
  color: #9e9e9e;

  &:hover {
    background: linear-gradient(145deg, #3a3a3a, #2a2a2a);
  }
}

.restore-btn {
  flex: 1;
  background: linear-gradient(145deg, #1a3a2a, #0f2a1a);
  border-color: #4caf50;
  color: #81c784;

  &:hover {
    background: linear-gradient(145deg, #2e5a3e, #1a3a2a);
    box-shadow: 0 0 8px rgba(76, 175, 80, 0.3);
  }
}

.delete-btn {
  flex: 1;
  background: linear-gradient(145deg, #3a1a1a, #2a0f0f);
  border-color: #8b0000;
  color: #ef9a9a;

  &:hover {
    background: linear-gradient(145deg, #5c1818, #3a1a1a);
    box-shadow: 0 0 8px rgba(139, 0, 0, 0.5);
  }
}

/* 物品/技能行样式 */
.item-row {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 8px;
  font-size: 0.8em;
  color: #e1bee7;
  margin-left: 8px;
  line-height: 1.4;
  border-bottom: 1px dashed rgba(136, 14, 79, 0.3);
  padding-bottom: 4px;
  margin-bottom: 4px;
}

.item-info {
  flex: 1;
}

.item-name {
  font-weight: 500;
}

.item-buttons {
  display: flex;
  gap: 4px;
}

/* 技能行样式 */
.skill-row {
  display: flex;
  flex-direction: column;
  gap: 2px;
  font-size: 0.8em;
  color: #e1bee7;
  margin-left: 8px;
  line-height: 1.4;
  border-bottom: 1px dashed rgba(136, 14, 79, 0.3);
  padding-bottom: 4px;
  margin-bottom: 4px;
}

.skill-header {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
}

.item-buttons {
  display: flex;
  gap: 4px;
}

.item-delete-btn {
  flex: none;
  font-size: 0.7em;
  padding: 2px 6px;
}

.use-btn {
  flex: none;
  font-size: 0.7em;
  padding: 2px 8px;
  background: linear-gradient(145deg, #1a3a2a, #0f2a1a);
  border-color: #4caf50;
  color: #81c784;

  &:hover {
    background: linear-gradient(145deg, #2e5a3e, #1a3a2a);
    box-shadow: 0 0 8px rgba(76, 175, 80, 0.3);
  }

  &:disabled {
    background: linear-gradient(145deg, #2a2a2a, #1a1a1a);
    border-color: #555;
    color: #666;
    cursor: not-allowed;
    box-shadow: none;
  }
}

/* NPC删除行 */
.npc-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.npc-actions {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-left: auto;
}

.npc-card {
  margin-bottom: 8px;
  padding-bottom: 6px;
  border-bottom: 1px dashed rgba(136, 14, 79, 0.3);

  &:last-child {
    border-bottom: none;
    margin-bottom: 0;
  }
}

.npc-name {
  color: #f48fb1;
  font-size: 0.8em;
  margin-top: 4px;
  margin-bottom: 2px;
}

.npc-delete-btn {
  font-size: 0.65em;
  padding: 2px 6px;
  flex: none;
}

/* 在场/离场人物卡片 */
.npc-card.present {
  border-left: 3px solid #4caf50;
  background: rgba(76, 175, 80, 0.08);
}

.npc-card.absent {
  border-left: 3px solid #78909c;
  opacity: 0.7;
}

.presence-tag {
  font-size: 0.65em;
  padding: 2px 6px;
  border-radius: 3px;
  margin-left: 8px;
  
  &.present {
    background: rgba(76, 175, 80, 0.3);
    color: #a5d6a7;
    border: 1px solid #4caf50;
  }
  
  &.absent {
    background: rgba(120, 144, 156, 0.3);
    color: #b0bec5;
    border: 1px solid #78909c;
  }
}

.presence-btn {
  font-size: 0.65em;
  padding: 2px 8px;
  margin-left: 8px;
  
  &.leave-btn {
    background: linear-gradient(135deg, #ef5350, #c62828);
    border-color: #ef5350;
    
    &:hover {
      box-shadow: 0 0 8px rgba(239, 83, 80, 0.5);
    }
  }
  
  &.arrive-btn {
    background: linear-gradient(135deg, #4caf50, #2e7d32);
    border-color: #4caf50;
    
    &:hover {
      box-shadow: 0 0 8px rgba(76, 175, 80, 0.5);
    }
  }
}

/* 技能描述 */
.skill-desc {
  color: #ab47bc;
  font-size: 0.9em;
  margin-left: 0;
}

.skill-cost {
  color: #64b5f6;
  font-size: 0.8em;
}

/* 技能等级徽章 */
.skill-grade-badge {
  display: inline-block;
  min-width: 18px;
  height: 18px;
  border-radius: 3px;
  font-size: 0.7em;
  font-weight: bold;
  text-align: center;
  line-height: 18px;
  margin-right: 4px;

  &.grade-d {
    background: linear-gradient(135deg, #616161, #424242);
    color: #e0e0e0;
    border: 1px solid #757575;
  }
  &.grade-c {
    background: linear-gradient(135deg, #4caf50, #2e7d32);
    color: #fff;
    border: 1px solid #81c784;
  }
  &.grade-b {
    background: linear-gradient(135deg, #2196f3, #1565c0);
    color: #fff;
    border: 1px solid #64b5f6;
  }
  &.grade-a {
    background: linear-gradient(135deg, #9c27b0, #6a1b9a);
    color: #fff;
    border: 1px solid #ba68c8;
  }
  &.grade-s {
    background: linear-gradient(135deg, #ff9800, #e65100);
    color: #fff;
    border: 1px solid #ffb74d;
    box-shadow: 0 0 6px rgba(255, 152, 0, 0.5);
  }
}

/* 蓝条样式 */
.mp-bar-wrapper {
  flex: 1;
  height: 16px;
  background: rgba(0, 0, 0, 0.4);
  border-radius: 8px;
  overflow: hidden;
  position: relative;
  border: 1px solid rgba(33, 150, 243, 0.5);
}

.mp-bar {
  height: 100%;
  background: linear-gradient(90deg, #1565c0, #2196f3, #64b5f6);
  transition: width 0.3s ease;
  box-shadow: 0 0 8px rgba(33, 150, 243, 0.5);
}

.mp-text {
  position: absolute;
  top: 50%;
  left: 8px;
  transform: translateY(-50%);
  font-size: 0.7em;
  color: #fff;
  text-shadow: 0 0 4px rgba(0, 0, 0, 0.8);
  white-space: nowrap;
}

.skill-unlock-info {
  margin-bottom: 6px;
}

.skill-cost-preview {
  color: #64b5f6;
  font-size: 0.75em;
}

.list-item {
  font-size: 0.8em;
  color: #e1bee7;
  margin-left: 8px;
  line-height: 1.4;
  border-bottom: 1px dashed rgba(136, 14, 79, 0.3);
  padding-bottom: 2px;
  margin-bottom: 2px;
}

/* 调试面板 */
.debug-panel {
  border: 1px dashed rgba(255, 213, 79, 0.5);
  background: rgba(255, 193, 7, 0.05);
}

.debug-buttons {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 6px;
}

.debug-btn {
  background: linear-gradient(145deg, #3a3a3a, #2a2a2a);
  border: 1px solid #555;
  border-radius: 4px;
  color: #ffd54f;
  font-size: 0.7em;
  padding: 4px 4px;
  cursor: pointer;
  transition: all 0.2s ease;

  &:hover {
    background: linear-gradient(145deg, #4a4a4a, #3a3a3a);
    border-color: #ffd54f;
    box-shadow: 0 0 8px rgba(255, 213, 79, 0.3);
  }

  &:active {
    transform: scale(0.95);
  }
}
